REPLACE INTO `eggs` (`id`, `uuid`, `nest_id`, `author`, `name`, `description`, `features`, `docker_images`, `file_denylist`, `update_url`, `config_files`, `config_startup`, `config_logs`, `config_stop`, `config_from`, `startup`, `script_container`, `copy_script_from`, `script_entry`, `script_is_privileged`, `script_install`, `created_at`, `updated_at`, `force_outgoing_ip`) VALUES (15,'0d7c0c33-620b-4723-bcaf-b2a7c49a337f',5,'bangsano135@gmail.com','Node.js V1','Jangan Lupa Support Terus Sano Official Ya😊',NULL,'{\"Nodejs 20\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_20\",\"Nodejs 24\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_24\",\"Nodejs 23\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_23\",\"Nodejs 22\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_22\",\"Nodejs 21\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_21\",\"Nodejs 19\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_19\",\"Nodejs 18\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_18\",\"Nodejs 17\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_17\",\"Nodejs 16\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_16\",\"Nodejs 15\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_15\",\"Nodejs 14\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_14\",\"Nodejs 13\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_13\",\"Nodejs 12\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_12\",\"Nodejs 11\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_11\",\"Nodejs 10\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_10\",\"Nodejs 9\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_9\",\"Nodejs 8\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_8\",\"Nodejs 7\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_7\",\"Nodejs 6\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_6\",\"Nodejs 5\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_5\",\"Nodejs 4\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_4\",\"Nodejs 3\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_3\",\"Nodejs 2\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_2\",\"Nodejs 1\":\"ghcr.io\\/parkervcp\\/yolks:nodejs_1\"}','[]',NULL,'{}','{\r\n    \"done\": \"running\"\r\n}','{}','^^C',NULL,'if [[ -d .git ]] && [[ {{AUTO_UPDATE}} == \"1\" ]]; then git pull; fi; if [[ ! -z ${NODE_PACKAGES} ]]; then /usr/local/bin/npm install ${NODE_PACKAGES}; fi; if [[ ! -z ${UNNODE_PACKAGES} ]]; then /usr/local/bin/npm uninstall ${UNNODE_PACKAGES}; fi; if [ -f /home/container/package.json ]; then /usr/local/bin/npm install; fi; if [[ ! -z ${CUSTOM_ENVIRONMENT_VARIABLES} ]]; then vars=$(echo ${CUSTOM_ENVIRONMENT_VARIABLES} | tr \";\" \"\\n\"); for line in $vars; do export $line; done fi; /usr/local/bin/${CMD_RUN};','node:14-buster-slim',NULL,'bash',1,'#!/bin/bash\n# Node.js App Installation Script\n#\n# Server Files: /mnt/server\napt update\napt install -y git curl jq file unzip make gcc g++ python python-dev libtool\n\nmkdir -p /mnt/server\ncd /mnt/server\n\nif [ \"${USER_UPLOAD}\" == \"true\" ] || [ \"${USER_UPLOAD}\" == \"1\" ]; then\n    echo -e \"assuming user knows what they are doing have a good day.\"\n    exit 0\nfi\n\nif [[ ${GIT_ADDRESS} != *.git ]]; then\n    GIT_ADDRESS=${GIT_ADDRESS}.git\nfi\n\nif [ -z \"${USERNAME}\" ] && [ -z \"${ACCESS_TOKEN}\" ]; then\n    echo -e \"using anon api call\"\nelse\n    GIT_ADDRESS=\"https://${USERNAME}:${ACCESS_TOKEN}@$(echo -e ${GIT_ADDRESS} | cut -d/ -f3-)\"\nfi\n\nif [ \"$(ls -A /mnt/server)\" ]; then\n    echo -e \"/mnt/server directory is not empty.\"\n    if [ -d .git ]; then\n        echo -e \".git directory exists\"\n        if [ -f .git/config ]; then\n            echo -e \"loading info from git config\"\n            ORIGIN=$(git config --get remote.origin.url)\n        else\n            echo -e \"files found with no git config\"\n            echo -e \"closing out without touching things to not break anything\"\n            exit 10\n        fi\n    fi\n\n    if [ \"${ORIGIN}\" == \"${GIT_ADDRESS}\" ]; then\n        echo \"pulling latest from github\"\n        git pull\n    fi\nelse\n    echo -e \"/mnt/server is empty.\\ncloning files into repo\"\n    if [ -z ${BRANCH} ]; then\n        echo -e \"cloning default branch\"\n        git clone ${GIT_ADDRESS} .\n    else\n        echo -e \"cloning ${BRANCH}\'\"\n        git clone --single-branch --branch ${BRANCH} ${GIT_ADDRESS} .\n    fi\nfi\n\necho \"Installing nodejs packages\"\nif [[ ! -z ${NODE_PACKAGES} ]]; then\n    /usr/local/bin/npm install ${NODE_PACKAGES}\nfi\n\nif [ -f /mnt/server/package.json ]; then\n    /usr/local/bin/npm install --production\nfi\n\necho -e \"install complete\"\nexit 0','2020-01-01 00:00:00','2020-01-01 00:00:00',0),(16,'dad0f6e9-c249-4fd3-b13a-a7f96f4ddb6b',5,'bangsano135@gmail.com','Python','Environment Python cerdas yang dioptimalkan. Server akan menginstal library secara otomatis dari file requirements.txt dan merutekan eksekusi ke file utama tanpa konfigurasi manual yang rumit.',NULL,'{\"Python 3.13 (Eksperimental)\":\"ghcr.io\\/ptero-eggs\\/yolks:python_3.13\",\"Python 3.12 (Paling Stabil & Direkomendasikan)\":\"ghcr.io\\/ptero-eggs\\/yolks:python_3.12\",\"Python 3.11\":\"ghcr.io\\/ptero-eggs\\/yolks:python_3.11\",\"Python 3.10\":\"ghcr.io\\/ptero-eggs\\/yolks:python_3.10\",\"Python 3.9\":\"ghcr.io\\/ptero-eggs\\/yolks:python_3.9\",\"Python 3.8\":\"ghcr.io\\/ptero-eggs\\/yolks:python_3.8\"}','[]',NULL,'{}','{\r\n    \"done\": [\r\n        \"running\",\r\n        \"started\",\r\n        \"ready\",\r\n        \"listening\",\r\n        \"online\",\r\n        \"berhasil\",\r\n        \"sukses\",\r\n        \"success\",\r\n        \"siap\",\r\n        \"connected\"\r\n    ]\r\n}','{}','^C',NULL,'if [[ -d .git ]] && [[ \"{{AUTO_UPDATE}}\" == \"1\" ]]; then git pull; fi; if [[ ! -z \"${UNPY_PACKAGES}\" ]]; then pip uninstall -y ${UNPY_PACKAGES}; fi; if [[ ! -z \"${PY_PACKAGES}\" ]]; then pip install -U --prefix .local ${PY_PACKAGES}; fi; if [[ -f /home/container/${REQUIREMENTS_FILE} ]]; then pip install -U --prefix .local -r ${REQUIREMENTS_FILE}; fi; /usr/local/bin/python /home/container/${PY_FILE}','python:3.8-slim-bookworm',NULL,'bash',1,'#!/bin/bash\n# Script Instalasi App Python\n# Server Files: /mnt/server\napt update\napt install -y git curl jq file unzip make gcc g++ libtool\n\nmkdir -p /mnt/server\ncd /mnt/server\n\nif [ \"${USER_UPLOAD}\" == \"true\" ] || [ \"${USER_UPLOAD}\" == \"1\" ]; then\n    echo -e \"✅ Mode Upload File Manual terdeteksi. Melewati proses sinkronisasi GitHub...\"\n    exit 0\nfi\n\nif [ -z \"${GIT_ADDRESS}\" ]; then\n    echo -e \"\\n❌ ERROR FATAL: Anda memilih opsi Download dari GitHub (USER_UPLOAD = 0),\"\n    echo -e \"tetapi Link Repositori (GIT_ADDRESS) KOSONG!\"\n    echo -e \"Silakan isi Link GitHub di panel, atau ubah \'Gunakan File Upload Manual\' menjadi 1.\\n\"\n    exit 1\nfi\n\nif [ ! -z \"${USERNAME}\" ] || [ ! -z \"${ACCESS_TOKEN}\" ]; then\n    if [ -z \"${USERNAME}\" ] || [ -z \"${ACCESS_TOKEN}\" ]; then\n        echo -e \"\\n❌ ERROR FATAL: Kredensial Private Repo Tidak Lengkap!\"\n        echo -e \"Anda mengisi salah satu antara USERNAME atau ACCESS_TOKEN, tetapi mengosongkan yang lainnya.\"\n        echo -e \"Keduanya WAJIB diisi bersamaan jika repo berstatus Private, atau KOSONGKAN keduanya jika repo Public.\\n\"\n        exit 1\n    fi\nfi\n\nif [[ ${GIT_ADDRESS} != *.git ]]; then\n    GIT_ADDRESS=${GIT_ADDRESS}.git\nfi\n\nif [ -z \"${USERNAME}\" ] && [ -z \"${ACCESS_TOKEN}\" ]; then\n    echo -e \"Mencoba akses GitHub anonim (Tanpa Token)...\"\nelse\n    GIT_ADDRESS=\"https://${USERNAME}:${ACCESS_TOKEN}@$(echo -e ${GIT_ADDRESS} | cut -d/ -f3-)\"\nfi\n\nif [ \"$(ls -A /mnt/server)\" ]; then\n    echo -e \"⚠️ Peringatan: Direktori /mnt/server tidak kosong.\"\n    if [ -d .git ]; then\n        echo -e \"Direktori .git ditemukan.\"\n        if [ -f .git/config ]; then\n            echo -e \"Memuat informasi dari git config...\"\n            ORIGIN=$(git config --get remote.origin.url)\n        else\n            echo -e \"❌ File ditemukan tetapi tidak ada git config.\"\n            echo -e \"Membatalkan proses instalasi agar tidak merusak file Anda yang sudah ada.\"\n            exit 10\n        fi\n    fi\n\n    if [ \"${ORIGIN}\" == \"${GIT_ADDRESS}\" ]; then\n        echo \"🔄 Menarik pembaruan (pull) terbaru dari GitHub...\"\n        git pull\n    fi\nelse\n    echo -e \"Direktori kosong.\\n⬇️ Memulai kloning file dari repositori...\"\n    if [ -z \"${BRANCH}\" ]; then\n        echo -e \"Mengkloning cabang utama (default branch)...\"\n        git clone ${GIT_ADDRESS} .\n    else\n        echo -e \"Mengkloning cabang spesifik: ${BRANCH}...\"\n        git clone --single-branch --branch ${BRANCH} ${GIT_ADDRESS} .\n    fi\nfi\n\nexport HOME=/mnt/server\n\necho \"📦 Menyiapkan environment Python...\"\n\nif [[ ! -z \"${UNPY_PACKAGES}\" ]]; then\n    echo \"🗑️ Menghapus paksa modul pip yang tidak diinginkan...\"\n    pip uninstall -y ${UNPY_PACKAGES}\nfi\n\nif [[ ! -z \"${PY_PACKAGES}\" ]]; then\n    echo \"Menginstal modul pip tambahan...\"\n    pip install -U --prefix .local ${PY_PACKAGES}\nfi\n\nif [ -f /mnt/server/${REQUIREMENTS_FILE} ]; then\n    echo \"Membaca dan menginstal dependensi dari ${REQUIREMENTS_FILE}...\"\n    pip install -U --prefix .local -r ${REQUIREMENTS_FILE}\nelse\n    echo \"ℹ️ Tidak ditemukan file ${REQUIREMENTS_FILE}, melewati proses instalasi massal.\"\nfi\n\necho -e \"✅ Instalasi selesai dengan sukses!\"\nexit 0','2020-01-01 00:00:00','2020-01-01 00:00:00',0),(17,'708ed659-fb2b-49f3-9635-8865869b459c',5,'bangsano135@gmail.com','Node.js V2 (Auto)','Environment Node.js cerdas dengan deteksi otomatis. Server akan mengunduh module NPM secara otomatis dan mencari perintah \'npm start\' dari package.json tanpa perlu konfigurasi manual dari klien.',NULL,'{\"Nodejs 20 (LTS - Direkomendasikan)\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_20\",\"Nodejs 25 (Eksperimental)\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_25\",\"Nodejs 24\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_24\",\"Nodejs 23\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_23\",\"Nodejs 22\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_22\",\"Nodejs 21\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_21\",\"Nodejs 19\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_19\",\"Nodejs 18\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_18\",\"Nodejs 17\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_17\",\"Nodejs 16\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_16\",\"Nodejs 14\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_14\",\"Nodejs 12\":\"ghcr.io\\/ptero-eggs\\/yolks:nodejs_12\"}','[]',NULL,'{}','{\r\n    \"done\": [\r\n        \"running\",\r\n        \"started\",\r\n        \"ready\",\r\n        \"listening\",\r\n        \"online\",\r\n        \"berhasil\",\r\n        \"sukses\",\r\n        \"success\",\r\n        \"siap\",\r\n        \"connected\"\r\n    ]\r\n}','{}','^C',NULL,'if [[ -d .git ]] && [[ \"{{AUTO_UPDATE}}\" == \"1\" ]]; then git pull; fi; if [[ ! -z ${UNNODE_PACKAGES} ]]; then /usr/local/bin/npm uninstall ${UNNODE_PACKAGES}; fi; if [[ ! -z ${NODE_PACKAGES} ]]; then /usr/local/bin/npm install ${NODE_PACKAGES}; fi; if [ -f /home/container/package.json ]; then /usr/local/bin/npm install; fi; if [[ \"{{USE_NPM_START}}\" == \"1\" ]] && [ -f /home/container/package.json ] && /usr/local/bin/node -e \"const p=require(\'/home/container/package.json\'); process.exit((p.scripts && p.scripts.start) ? 0 : 1);\" 2>/dev/null; then /usr/local/bin/npm start; elif [[ \"${MAIN_FILE}\" == \"*.js\" ]]; then /usr/local/bin/node \"/home/container/${MAIN_FILE}\" ${NODE_ARGS}; else /usr/local/bin/ts-node --esm \"/home/container/${MAIN_FILE}\" ${NODE_ARGS}; fi','node:20-trixie-slim',NULL,'bash',1,'#!/bin/bash\n# Script Instalasi App Node.js\n# Server Files: /mnt/server\napt update\napt install -y git curl jq file unzip make gcc g++ python3 python3-dev python3-pip libtool\n\necho -e \"Memperbarui NPM ke versi terbaru. Mohon tunggu...\"\nnpm install npm@latest --location=global\n\nmkdir -p /mnt/server\ncd /mnt/server\n\nif [ \"${USER_UPLOAD}\" == \"true\" ] || [ \"${USER_UPLOAD}\" == \"1\" ]; then\n    echo -e \"✅ Mode Upload File Manual terdeteksi. Melewati proses sinkronisasi GitHub...\"\n    exit 0\nfi\n\nif [ -z \"${GIT_ADDRESS}\" ]; then\n    echo -e \"\\n❌ ERROR FATAL: Anda memilih opsi Download dari GitHub (USER_UPLOAD = 0),\"\n    echo -e \"tetapi Link Repositori (GIT_ADDRESS) KOSONG!\"\n    echo -e \"Silakan isi Link GitHub di panel, atau ubah \'Gunakan File Upload Manual\' menjadi 1.\\n\"\n    exit 1\nfi\n\nif [ ! -z \"${USERNAME}\" ] || [ ! -z \"${ACCESS_TOKEN}\" ]; then\n    if [ -z \"${USERNAME}\" ] || [ -z \"${ACCESS_TOKEN}\" ]; then\n        echo -e \"\\n❌ ERROR FATAL: Kredensial Private Repo Tidak Lengkap!\"\n        echo -e \"Anda mengisi salah satu antara USERNAME atau ACCESS_TOKEN, tetapi mengosongkan yang lainnya.\"\n        echo -e \"Keduanya WAJIB diisi bersamaan jika repo berstatus Private, atau KOSONGKAN keduanya jika repo Public.\\n\"\n        exit 1\n    fi\nfi\n\nif [[ ${GIT_ADDRESS} != *.git ]]; then\n    GIT_ADDRESS=${GIT_ADDRESS}.git\nfi\n\nif [ -z \"${USERNAME}\" ] && [ -z \"${ACCESS_TOKEN}\" ]; then\n    echo -e \"Mencoba akses GitHub anonim (Tanpa Token)...\"\nelse\n    GIT_ADDRESS=\"https://${USERNAME}:${ACCESS_TOKEN}@$(echo -e ${GIT_ADDRESS} | cut -d/ -f3-)\"\nfi\n\nif [ \"$(ls -A /mnt/server)\" ]; then\n    echo -e \"⚠️ Peringatan: Direktori /mnt/server tidak kosong.\"\n    if [ -d .git ]; then\n        echo -e \"Direktori .git ditemukan.\"\n        if [ -f .git/config ]; then\n            echo -e \"Memuat informasi dari git config...\"\n            ORIGIN=$(git config --get remote.origin.url)\n        else\n            echo -e \"❌ File ditemukan tetapi tidak ada git config.\"\n            echo -e \"Membatalkan proses instalasi agar tidak merusak file Anda yang sudah ada.\"\n            exit 10\n        fi\n    fi\n\n    if [ \"${ORIGIN}\" == \"${GIT_ADDRESS}\" ]; then\n        echo \"🔄 Menarik pembaruan (pull) terbaru dari GitHub...\"\n        git pull\n    fi\nelse\n    echo -e \"Direktori kosong.\\n⬇️ Memulai kloning file dari repositori...\"\n    if [ -z \"${BRANCH}\" ]; then\n        echo -e \"Mengkloning cabang utama (default branch)...\"\n        git clone ${GIT_ADDRESS} .\n    else\n        echo -e \"Mengkloning cabang spesifik: ${BRANCH}...\"\n        git clone --single-branch --branch ${BRANCH} ${GIT_ADDRESS} .\n    fi\nfi\n\necho \"📦 Menginstal library / packages Node.js...\"\nif [[ ! -z \"${NODE_PACKAGES}\" ]]; then\n    /usr/local/bin/npm install ${NODE_PACKAGES}\nfi\n\nif [ -f /mnt/server/package.json ]; then\n    /usr/local/bin/npm install --production\nfi\n\necho -e \"✅ Instalasi selesai dengan sukses!\"\nexit 0','2020-01-01 00:00:00','2020-01-01 00:00:00',0);
