REPLACE INTO `egg_variables` (`id`, `egg_id`, `name`, `description`, `env_variable`, `default_value`, `user_viewable`, `user_editable`, `rules`, `created_at`, `updated_at`) VALUES (71,15,'Git Repo Address','GitHub Repo to clone\n\nI.E. https://github.com/user_name/repo_name','GIT_ADDRESS','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(72,15,'Install Branch','The branch to install.','BRANCH','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(73,15,'Git Username','Username to auth with git.','USERNAME','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(74,15,'Git Access Token','Password to use with git.\n\nIt\'s best practice to use a Personal Access Token.\nhttps://github.com/settings/tokens\nhttps://gitlab.com/-/profile/personal_access_tokens','ACCESS_TOKEN','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(75,15,'Command Run','Command Start Bot','CMD_RUN','npm start',1,1,'required|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(76,16,'Gunakan File Upload Manual?','Aktifkan saklar ini jika Anda mengupload file bot sendiri secara manual. Matikan saklar ini jika Anda ingin mendownload script otomatis dari GitHub. PENTING: Mode download dari GitHub HANYA akan terpicu jika Anda menekan tombol \"Reinstall Server\" di menu Settings (paling bawah).','USER_UPLOAD','1',1,1,'required|boolean','2020-01-01 00:00:00','2020-01-01 00:00:00'),(77,16,'File Utama Script Python (Entry File)','Nama file utama yang bertugas menyalakan bot Anda. Contoh: main.py, app.py, atau bot.py','PY_FILE','main.py',1,1,'required|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(78,16,'File Library / Requirements','Nama file yang berisi daftar library yang dibutuhkan script (standarnya requirements.txt). Server akan mendeteksi dan menginstalnya secara otomatis.','REQUIREMENTS_FILE','requirements.txt',1,1,'required|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(79,16,'Link Repositori Git (Opsional)','Alamat link Repository GitHub (contoh: https://github.com/username/nama_repo). PENTING: Agar aksi Anda dalam mengisi/mengubah link Repository Github di kolom ini dapat terpicu, Anda WAJIB menekan tombol \"Reinstall Server\" di menu Settings (paling bawah) agar sistem mengunduhnya. Jika Anda tidak melakukannya, tidak akan ada yang terjadi, sistem tidak akan mengunduh file apapun dari repository github yang Anda tetapkan. Dan jika saklar File Upload Manual sedang aktif, input pada kolom ini akan diabaikan.','GIT_ADDRESS','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(80,16,'Update Otomatis dari GitHub?','Aktifkan saklar ini agar bot otomatis menarik pembaruan (git pull) dari GitHub setiap kali server dinyalakan.','AUTO_UPDATE','0',1,1,'required|boolean','2020-01-01 00:00:00','2020-01-01 00:00:00'),(81,16,'Cabang Git / Branch (Opsional)','Spesifik branch GitHub yang ingin diinstal. Kosongkan untuk menggunakan branch utama (main/master). PENTING: Perubahan di sini butuh klik \"Reinstall Server\" di menu Settings (paling bawah) agar berlaku.','BRANCH','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(82,16,'Username GitHub (Private Repo)','Isi username GitHub Anda HANYA jika script yang didownload bersifat Repository Private. PENTING: Perubahan di sini butuh klik \"Reinstall Server\" di menu Settings (paling bawah) agar berlaku.','USERNAME','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(83,16,'Token Akses GitHub (Private Repo)','Isi dengan Personal Access Token (PAT) HANYA jika repository Anda Private. PENTING: Perubahan di sini butuh klik \"Reinstall Server\" di menu Settings (paling bawah) agar berlaku.','ACCESS_TOKEN','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(84,16,'Tambahan Module Python (Opsional)','Install paksa (pip install) modul Python tambahan yang tidak ada di file Requirements bawaan Anda. Pisahkan dengan spasi jika banyak (contoh: pyrogram flask requests).','PY_PACKAGES','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(85,16,'Hapus Module Python (Opsional)','Hapus paksa modul tertentu. Pisahkan dengan spasi jika banyak.','UNPY_PACKAGES','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(86,17,'Gunakan File Upload Manual?','Aktifkan saklar ini jika Anda mengupload file bot sendiri secara manual. Matikan saklar ini jika Anda ingin mendownload script otomatis dari GitHub. PENTING: Mode download dari GitHub HANYA akan terpicu jika Anda menekan tombol \"Reinstall Server\" di menu Settings (paling bawah).','USER_UPLOAD','1',1,1,'required|boolean','2020-01-01 00:00:00','2020-01-01 00:00:00'),(87,17,'Gunakan NPM Start (Otomatis)?','Aktifkan saklar ini agar server memprioritaskan eksekusi command start dari package.json (jika ada). Matikan saklar ini untuk memaksa server mengabaikan package.json dan murni menjalankan [File Utama] beserta [Argumen Node] yang Anda tentukan di bawah.','USE_NPM_START','1',1,1,'required|boolean','2020-01-01 00:00:00','2020-01-01 00:00:00'),(88,17,'File Utama Script (Entry File)','Nama file eksekutor Anda (mendukung ekstensi .js dan .ts, contoh: index.js atau app.ts). Jika saklar Gunakan NPM Start sedang aktif dan package.json valid, input pada kolom ini akan diabaikan.','MAIN_FILE','index.js',1,1,'required|string|max:16','2020-01-01 00:00:00','2020-01-01 00:00:00'),(89,17,'Argumen Node Tambahan (Opsional)','Argumen ekstra. Logika di sistem: \"node [File_Utama] ...[Argumen_Tambahan]\". Contoh pengisian: \"--max-old-space-size=1024\" (mengatur batas RAM), \"<url> <time> <rate> <threads>\" (Eksekusi DD*S), atau lainnya (tanpa tanda kutip ya). Nanti hasilnya menjadi seperti ini, contoh: \"node index.js --max-old-space-size=1024\". Biarkan KOSONG jika Anda tidak paham atau tidak diperlukan.','NODE_ARGS','',1,1,'nullable|string|max:64','2020-01-01 00:00:00','2020-01-01 00:00:00'),(90,17,'Link Repositori Git (Opsional)','Alamat link Repository GitHub (contoh: https://github.com/username/nama_repo). PENTING: Agar aksi Anda dalam mengisi/mengubah link Repository Github di kolom ini dapat terpicu, Anda WAJIB menekan tombol \"Reinstall Server\" di menu Settings (paling bawah) agar sistem mengunduhnya. Jika Anda tidak melakukannya, tidak akan ada yang terjadi, sistem tidak akan mengunduh file apapun dari repository github yang Anda tetapkan. Dan jika saklar File Upload Manual sedang aktif, input pada kolom ini akan diabaikan.','GIT_ADDRESS','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(91,17,'Update Otomatis dari GitHub?','Aktifkan saklar ini agar bot otomatis menarik pembaruan (git pull) dari GitHub setiap kali server dinyalakan.','AUTO_UPDATE','0',1,1,'required|boolean','2020-01-01 00:00:00','2020-01-01 00:00:00'),(92,17,'Cabang Git / Branch (Opsional)','Spesifik branch GitHub yang ingin diinstal. Kosongkan untuk menggunakan branch utama (main/master). PENTING: Perubahan di sini butuh klik \"Reinstall Server\" di menu Settings (paling bawah) agar berlaku.','BRANCH','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(93,17,'Username GitHub (Private Repo)','Isi username GitHub Anda HANYA jika script yang didownload bersifat Repository Private. PENTING: Perubahan di sini butuh klik \"Reinstall Server\" di menu Settings (paling bawah) agar berlaku.','USERNAME','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(94,17,'Token Akses GitHub (Private Repo)','Isi dengan Personal Access Token (PAT) HANYA jika repository Anda Private. PENTING: Perubahan di sini butuh klik \"Reinstall Server\" di menu Settings (paling bawah) agar berlaku.','ACCESS_TOKEN','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(95,17,'Tambahan Package NPM (Opsional)','Install paksa (npm install) modul tambahan yang tidak ada di file package.json bawaan Anda. Pisahkan dengan spasi jika banyak (contoh: axios moment ssh).','NODE_PACKAGES','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00'),(96,17,'Hapus Package NPM (Opsional)','Hapus paksa modul tertentu. Pisahkan dengan spasi jika banyak.','UNNODE_PACKAGES','',1,1,'nullable|string','2020-01-01 00:00:00','2020-01-01 00:00:00');
